import kotlinx.coroutines.*

suspend fun fetchUserProfile(userId: String): UserProfile = supervisorScope {
    val coreData = async { userService.getCoreData(userId) }
    val badges = async { badgeService.getBadges(userId) }  // optional enrichment
    val streak = async { streakService.getStreak(userId) } // optional enrichment

    val core = coreData.await() // throws if core fails — propagates up
    UserProfile(
        core = core,
        badges = runCatching { badges.await() }.getOrNull(),
        streak = runCatching { streak.await() }.getOrNull()
    )
}

// Ktor + Exposed + kotlinx.serialization — idiomatic stack
suspend fun getUser(id: Int): User? = newSuspendedTransaction(Dispatchers.IO) {
    Users.selectAll().where { Users.id eq id }
        .singleOrNull()
        ?.let { User(it[Users.id], it[Users.name], it[Users.email]) }
}

// Arrow typed error — no exceptions in service layer
suspend fun findUser(id: Int): Either<UserError, User> = either {
    getUser(id) ?: raise(UserError.NotFound(id))
}

fun Application.configureRouting(userRepo: UserRepository) {
    routing {
        get("/users/{id}") {
            val id = call.parameters["id"]?.toLong()
                ?: return@get call.respond(HttpStatusCode.BadRequest)
            // newSuspendedTransaction suspends the coroutine — no thread parked
            val user = newSuspendedTransaction(Dispatchers.IO) {
                userRepo.findById(id)
            }
            call.respond(user ?: HttpStatusCode.NotFound)
        }
    }
}

